import { useState, useEffect, useRef } from "react";

const LOGO_B64 = "";

/* ═══════════════════ REACTBITS COMPONENTS ═══════════════════ */

// 1. BlurText
const BlurText = ({ text, className = "", delay = 0 }) => {
  const [v, setV] = useState(false); const ref = useRef();
  useEffect(() => { const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.1 }); if (ref.current) o.observe(ref.current); return () => o.disconnect(); }, []);
  return <span ref={ref} className={className} style={{ display: "inline" }}>{text.split(" ").map((w, i) => <span key={i} style={{ display: "inline-block", marginRight: "0.25em", opacity: v ? 1 : 0, filter: v ? "blur(0)" : "blur(10px)", transform: v ? "translateY(0)" : "translateY(14px)", transition: `opacity 0.6s ${delay + i * 0.09}s, filter 0.6s ${delay + i * 0.09}s, transform 0.6s ${delay + i * 0.09}s` }}>{w}</span>)}</span>;
};

// 2. GlitchText
const GlitchText = ({ text, className = "" }) => {
  const [g, setG] = useState(false);
  const go = () => { setG(true); setTimeout(() => setG(false), 500); };
  return <span className={className} onMouseEnter={go} style={{ position: "relative", display: "inline-block" }}>{text}{g && <><span style={{ position: "absolute", top: 0, left: 0, color: "#00ff88", clipPath: "inset(20% 0 50% 0)", transform: "translateX(-3px)", opacity: 0.7, pointerEvents: "none", animation: "g1 0.1s steps(2) infinite" }}>{text}</span><span style={{ position: "absolute", top: 0, left: 0, color: "#ff2244", clipPath: "inset(55% 0 10% 0)", transform: "translateX(3px)", opacity: 0.7, pointerEvents: "none", animation: "g2 0.12s steps(2) 0.04s infinite" }}>{text}</span></>}</span>;
};

// 3. ShinyText
const ShinyText = ({ text, className = "" }) => <span className={className} style={{ background: "linear-gradient(105deg,#ff2244 0%,#ff2244 30%,#ff8899 45%,#ff2244 60%,#ff2244 100%)", backgroundSize: "200% auto", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", animation: "shine 3s linear infinite", display: "inline-block" }}>{text}</span>;

// 4. GreenShiny
const GreenShiny = ({ text, className = "" }) => <span className={className} style={{ background: "linear-gradient(105deg,#00cc44 0%,#00cc44 30%,#88ffbb 45%,#00cc44 60%,#00cc44 100%)", backgroundSize: "200% auto", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", animation: "shine 3s linear infinite", display: "inline-block" }}>{text}</span>;

// 5. CountUp
const CountUp = ({ end, prefix = "", suffix = "", duration = 2000 }) => {
  const [v, setV] = useState(0); const ref = useRef(); const s = useRef(false);
  useEffect(() => { const o = new IntersectionObserver(([e]) => { if (e.isIntersecting && !s.current) { s.current = true; const t0 = performance.now(); const step = (n) => { const p = Math.min((n - t0) / duration, 1); setV(Math.floor((1 - Math.pow(1 - p, 3)) * end)); if (p < 1) requestAnimationFrame(step); }; requestAnimationFrame(step); } }, { threshold: 0.5 }); if (ref.current) o.observe(ref.current); return () => o.disconnect(); }, [end, duration]);
  return <span ref={ref}>{prefix}{v.toLocaleString("en-IN")}{suffix}</span>;
};

// 6. TypeWriter
const TypeWriter = ({ text, speed = 45 }) => {
  const [d, setD] = useState(""); const [done, setDone] = useState(false); const ref = useRef(); const s = useRef(false);
  useEffect(() => { const o = new IntersectionObserver(([e]) => { if (e.isIntersecting && !s.current) { s.current = true; let i = 0; const iv = setInterval(() => { setD(text.slice(0, ++i)); if (i >= text.length) { clearInterval(iv); setDone(true); } }, speed); } }, { threshold: 0.5 }); if (ref.current) o.observe(ref.current); return () => o.disconnect(); }, [text, speed]);
  return <span ref={ref}>{d}{!done && <span style={{ borderRight: "2px solid #ff2244", animation: "blink 1s infinite", marginLeft: 1 }}>&nbsp;</span>}</span>;
};

// 7. SplitText
const SplitText = ({ text, className = "", stagger = 0.035, triggerDelay = 0 }) => {
  const [v, setV] = useState(false); const ref = useRef();
  useEffect(() => { const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.1 }); if (ref.current) o.observe(ref.current); return () => o.disconnect(); }, []);
  return <span ref={ref} className={className} style={{ display: "inline-block" }}>{text.split("").map((c, i) => <span key={i} style={{ display: "inline-block", opacity: v ? 1 : 0, transform: v ? "translateY(0) rotateX(0)" : "translateY(24px) rotateX(-90deg)", transition: `opacity 0.4s ${triggerDelay + i * stagger}s, transform 0.5s ${triggerDelay + i * stagger}s`, whiteSpace: c === " " ? "pre" : "normal" }}>{c === " " ? "\u00A0" : c}</span>)}</span>;
};

// 8. Aurora
const Aurora = ({ colors = ["rgba(255,34,68,0.06)", "rgba(0,204,68,0.04)", "rgba(255,34,68,0.03)"] }) => (
  <div style={{ position: "absolute", inset: 0, overflow: "hidden", zIndex: 0 }}>
    <div style={{ position: "absolute", width: "160%", height: "160%", top: "-30%", left: "-30%", background: `radial-gradient(ellipse 60% 40% at 30% 40%, ${colors[0]} 0%, transparent 60%), radial-gradient(ellipse 50% 60% at 70% 60%, ${colors[1]} 0%, transparent 60%), radial-gradient(ellipse 80% 50% at 50% 80%, ${colors[2]} 0%, transparent 60%)`, animation: "aurora 14s ease-in-out infinite alternate" }} />
  </div>
);

// 9. Particles
const Particles = ({ count = 40 }) => {
  const pts = useRef(Array.from({ length: count }, () => ({ x: Math.random() * 100, y: Math.random() * 100, r: Math.random() * 1.5 + 0.5, dur: 12 + Math.random() * 18, del: Math.random() * 12, ox: (Math.random() - 0.5) * 5, oy: (Math.random() - 0.5) * 5, red: Math.random() > 0.5 }))).current;
  return <svg style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 0 }}>{pts.map((p, i) => <circle key={i} cx={`${p.x}%`} cy={`${p.y}%`} r={p.r} fill={p.red ? "rgba(255,34,68,0.35)" : "rgba(0,204,68,0.3)"}><animate attributeName="cx" values={`${p.x}%;${p.x + p.ox}%;${p.x}%`} dur={`${p.dur}s`} begin={`${p.del}s`} repeatCount="indefinite" /><animate attributeName="cy" values={`${p.y}%;${p.y + p.oy}%;${p.y}%`} dur={`${p.dur * 1.2}s`} begin={`${p.del}s`} repeatCount="indefinite" /><animate attributeName="opacity" values="0;0.7;0" dur={`${p.dur * 0.9}s`} begin={`${p.del}s`} repeatCount="indefinite" /></circle>)}</svg>;
};

// 10. GridBg
const GridBg = () => <div style={{ position: "absolute", inset: 0, zIndex: 0, backgroundImage: "linear-gradient(rgba(255,34,68,0.04) 1px, transparent 1px), linear-gradient(90deg, rgba(0,204,68,0.04) 1px, transparent 1px)", backgroundSize: "55px 55px", maskImage: "radial-gradient(ellipse 80% 70% at 50% 50%, black 40%, transparent 100%)" }} />;

// 11. MagneticButton
const MagneticButton = ({ children, onClick, style = {} }) => {
  const ref = useRef();
  const onMove = (e) => { const r = ref.current.getBoundingClientRect(); ref.current.style.transform = `translate(${(e.clientX - r.left - r.width / 2) * 0.22}px, ${(e.clientY - r.top - r.height / 2) * 0.22}px)`; };
  const onLeave = () => { ref.current.style.transform = "translate(0,0)"; };
  return <button ref={ref} onClick={onClick} onMouseMove={onMove} onMouseLeave={onLeave} style={{ transition: "transform 0.25s cubic-bezier(0.23,1,0.32,1)", ...style }}>{children}</button>;
};

// 12. TiltCard
const TiltCard = ({ children, style = {} }) => {
  const ref = useRef();
  const onMove = (e) => { const r = ref.current.getBoundingClientRect(); const x = (e.clientX - r.left) / r.width - 0.5, y = (e.clientY - r.top) / r.height - 0.5; ref.current.style.transform = `perspective(800px) rotateX(${-y * 9}deg) rotateY(${x * 9}deg) translateY(-5px)`; ref.current.style.boxShadow = `${-x * 16}px ${-y * 16}px 36px rgba(255,34,68,0.1), ${x * 8}px ${y * 8}px 20px rgba(0,204,68,0.06)`; };
  const onLeave = () => { ref.current.style.transform = "perspective(800px) rotateX(0) rotateY(0) translateY(0)"; ref.current.style.boxShadow = "none"; };
  return <div ref={ref} onMouseMove={onMove} onMouseLeave={onLeave} style={{ transition: "transform 0.15s ease, box-shadow 0.15s ease", ...style }}>{children}</div>;
};

// 13. AnimatedList
const AnimatedList = ({ items, renderItem }) => {
  const [v, setV] = useState(false); const ref = useRef();
  useEffect(() => { const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.1 }); if (ref.current) o.observe(ref.current); return () => o.disconnect(); }, []);
  return <div ref={ref}>{items.map((item, i) => <div key={i} style={{ opacity: v ? 1 : 0, transform: v ? "translateX(0)" : "translateX(-24px)", transition: `opacity 0.5s ${i * 0.07}s, transform 0.5s ${i * 0.07}s` }}>{renderItem(item, i)}</div>)}</div>;
};

// 14. ScrollReveal
const SR = ({ children, delay = 0, dir = "up" }) => {
  const [v, setV] = useState(false); const ref = useRef();
  useEffect(() => { const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.08 }); if (ref.current) o.observe(ref.current); return () => o.disconnect(); }, []);
  const from = { up: "translateY(40px)", down: "translateY(-40px)", left: "translateX(-40px)", right: "translateX(40px)" };
  return <div ref={ref} style={{ opacity: v ? 1 : 0, transform: v ? "translate(0)" : from[dir], transition: `opacity 0.7s ${delay}s, transform 0.7s ${delay}s cubic-bezier(0.16,1,0.3,1)` }}>{children}</div>;
};

// 15. Marquee
const Marquee = ({ items }) => (
  <div style={{ overflow: "hidden", whiteSpace: "nowrap", padding: "14px 0", borderTop: "1px solid rgba(255,34,68,0.15)", borderBottom: "1px solid rgba(0,204,68,0.15)", background: "rgba(255,255,255,0.02)" }}>
    <span style={{ display: "inline-block", animation: "marquee 22s linear infinite" }}>
      {[...items, ...items].map((item, i) => <span key={i} style={{ marginRight: "52px", fontSize: "0.68rem", letterSpacing: "3px", textTransform: "uppercase", fontFamily: "'DM Mono',monospace", color: i % 2 === 0 ? "rgba(255,34,68,0.55)" : "rgba(0,204,68,0.55)" }}><span style={{ marginRight: "18px", opacity: 0.4 }}>◆</span>{item}</span>)}
    </span>
  </div>
);

// 16. Countdown
const Countdown = () => {
  const [t, setT] = useState({ d: 0, h: 0, m: 0, s: 0 });
  useEffect(() => { const tick = () => { const diff = new Date("2026-03-28T07:30:00") - new Date(); if (diff <= 0) return; setT({ d: Math.floor(diff / 86400000), h: Math.floor((diff % 86400000) / 3600000), m: Math.floor((diff % 3600000) / 60000), s: Math.floor((diff % 60000) / 1000) }); }; tick(); const iv = setInterval(tick, 1000); return () => clearInterval(iv); }, []);
  const Unit = ({ val, label, color }) => <div style={{ textAlign: "center", minWidth: 70 }}><div style={{ fontFamily: "'Orbitron',monospace", fontSize: "clamp(2.2rem,5vw,3.8rem)", fontWeight: 700, color, lineHeight: 1 }}>{String(val).padStart(2, "0")}</div><div style={{ fontFamily: "'DM Mono',monospace", fontSize: "0.58rem", letterSpacing: "3px", textTransform: "uppercase", color: "rgba(255,255,255,0.35)", marginTop: 6 }}>{label}</div></div>;
  const Sep = ({ color }) => <div style={{ fontFamily: "'Orbitron',monospace", fontSize: "3rem", color, opacity: 0.5, alignSelf: "flex-start", paddingTop: 4, animation: "blink 1s infinite" }}>:</div>;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: "clamp(8px,2vw,24px)" }}>
      <Unit val={t.d} label="Days" color="#ff2244" /><Sep color="#ff2244" />
      <Unit val={t.h} label="Hours" color="#f5f0e8" /><Sep color="#00cc44" />
      <Unit val={t.m} label="Mins" color="#f5f0e8" /><Sep color="#ff2244" />
      <Unit val={t.s} label="Secs" color="#00cc44" />
    </div>
  );
};

// 17. CursorTrail
const CursorTrail = () => {
  const [trails, setTrails] = useState([]); const cnt = useRef(0);
  const syms = ["₹", "$", "%", "∑", "π", "↑", "↓", "≈", "∞", "0", "1"];
  useEffect(() => {
    const h = (e) => { if (cnt.current++ % 4 !== 0) return; const id = Date.now() + Math.random(); const red = Math.random() > 0.5; setTrails(t => [...t.slice(-18), { id, x: e.clientX, y: e.clientY, sym: syms[Math.floor(Math.random() * syms.length)], red }]); setTimeout(() => setTrails(t => t.filter(tr => tr.id !== id)), 900); };
    window.addEventListener("mousemove", h); return () => window.removeEventListener("mousemove", h);
  }, []);
  return <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 9999 }}>{trails.map(tr => <div key={tr.id} style={{ position: "absolute", left: tr.x, top: tr.y, fontFamily: "'DM Mono',monospace", fontSize: 9 + Math.random() * 8, color: tr.red ? "rgba(255,34,68,0.65)" : "rgba(0,204,68,0.65)", transform: "translate(-50%,-50%)", animation: "trailFade 0.9s forwards" }}>{tr.sym}</div>)}</div>;
};

// 18. GlowBorder
const GlowBorder = ({ children, style = {}, hovered = false, color = "#ff2244" }) => (
  <div style={{ position: "relative", ...style }}>
    <div style={{ position: "absolute", inset: -1, background: `linear-gradient(90deg, transparent, ${color}, transparent)`, backgroundSize: "200% 100%", animation: hovered ? "glowSweep 1.8s linear infinite" : "none", opacity: hovered ? 1 : 0, transition: "opacity 0.3s", pointerEvents: "none", zIndex: 0 }} />
    <div style={{ position: "relative", zIndex: 1, height: "100%" }}>{children}</div>
  </div>
);

// 19. PulseRing
const PulseRing = ({ children, color = "#ff2244" }) => (
  <div style={{ position: "relative", display: "inline-block" }}>
    <div style={{ position: "absolute", inset: -4, border: `1px solid ${color}80`, borderRadius: 2, animation: "pulse1 2s ease-out infinite" }} />
    <div style={{ position: "absolute", inset: -10, border: `1px solid ${color}40`, borderRadius: 2, animation: "pulse1 2s ease-out 0.5s infinite" }} />
    {children}
  </div>
);

// 20. GlowText (new!)
const GlowText = ({ text, color = "#ff2244" }) => (
  <span style={{ color, textShadow: `0 0 20px ${color}80, 0 0 40px ${color}40` }}>{text}</span>
);

