          <div style={{ fontFamily: "'DM Mono',monospace", fontSize: "0.76rem", color: "var(--dim)", letterSpacing: "2px", animation: "fadeUp 0.8s 0.9s both" }}>
            <span style={{ color: "#ff2244" }}>28th MARCH 2026</span>
          </div>

