/* ─── Cursor Dot ─── */
function CursorDot() {
  const dot = useRef(); const ring = useRef(); const mx = useRef(0); const my = useRef(0); const rx = useRef(0); const ry = useRef(0);
  useEffect(() => {
    const mv = (e) => { mx.current = e.clientX; my.current = e.clientY; if (dot.current) { dot.current.style.left = e.clientX + "px"; dot.current.style.top = e.clientY + "px"; } };
    window.addEventListener("mousemove", mv);
    let af;
    const loop = () => { rx.current += (mx.current - rx.current) * 0.13; ry.current += (my.current - ry.current) * 0.13; if (ring.current) { ring.current.style.left = rx.current + "px"; ring.current.style.top = ry.current + "px"; } af = requestAnimationFrame(loop); };
    af = requestAnimationFrame(loop);
    return () => { window.removeEventListener("mousemove", mv); cancelAnimationFrame(af); };
  }, []);
  return <>
    <div ref={dot} style={{ position: "fixed", width: 8, height: 8, background: "#ff2244", borderRadius: "50%", pointerEvents: "none", zIndex: 9999, transform: "translate(-50%,-50%)", mixBlendMode: "normal" }} />
    <div ref={ring} style={{ position: "fixed", width: 32, height: 32, border: "1px solid rgba(255,34,68,0.5)", borderRadius: "50%", pointerEvents: "none", zIndex: 9998, transform: "translate(-50%,-50%)", opacity: 0.6 }} />
  </>;
}

/* ─── Nav ─── */
function Nav() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => { const h = () => setScrolled(window.scrollY > 50); window.addEventListener("scroll", h); return () => window.removeEventListener("scroll", h); }, []);
  return (
    <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 500, padding: "16px clamp(20px,5vw,64px)", display: "flex", alignItems: "center", justifyContent: "space-between", background: scrolled ? "rgba(6,8,16,0.95)" : "transparent", backdropFilter: scrolled ? "blur(16px)" : "none", borderBottom: scrolled ? "1px solid rgba(255,34,68,0.12)" : "1px solid transparent", transition: "background 0.3s, border-color 0.3s" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <div style={{ fontFamily: "'Orbitron',monospace", fontSize: "1.2rem", fontWeight: 900, color: "#ff2244", textShadow: "0 0 16px rgba(255,34,68,0.5)" }}>Finovate<span style={{ color: "#00cc44" }}>X</span></div>
      </div>
      <div style={{ display: "flex", gap: "clamp(14px,2.5vw,32px)", alignItems: "center" }}>
        {["Events", "Schedule", "Judging", "Register"].map(l => (
          <a key={l} href={`#${l.toLowerCase()}`} style={{ fontFamily: "'DM Mono',monospace", fontSize: "0.68rem", letterSpacing: "2px", textTransform: "uppercase", color: "var(--dim)", textDecoration: "none", transition: "color 0.2s, text-shadow 0.2s" }} onMouseEnter={e => { e.target.style.color = "#ff2244"; e.target.style.textShadow = "0 0 10px rgba(255,34,68,0.5)"; }} onMouseLeave={e => { e.target.style.color = "var(--dim)"; e.target.style.textShadow = "none"; }}>
            {l}
          </a>
        ))}
      </div>
    </nav>
  );
}

